const supabaseLeads = $node['Fetch All Active Leads'].json;
const odooResponse = $node['Fetch Odoo Leads'].json;

const leads = Array.isArray(supabaseLeads) ? supabaseLeads : [];
const odooLeads = odooResponse?.result || [];

// Build pipeline summary
const pipeline = {
  total: leads.length,
  by_priority: { HOT: 0, WARM: 0, COLD: 0, unscored: 0 },
  by_status: {},
  avg_score: 0,
  total_potential_revenue: 0,
  leads_last_24h: 0,
  odoo_leads: odooLeads.length
};

const now = Date.now();
let scoreSum = 0, scoreCount = 0;

leads.forEach(l => {
  pipeline.by_priority[l.ai_priority || 'unscored']++;
  pipeline.by_status[l.status || 'unknown'] = (pipeline.by_status[l.status || 'unknown'] || 0) + 1;
  if (l.ai_score) { scoreSum += l.ai_score; scoreCount++; }
  if (l.budget_max) pipeline.total_potential_revenue += parseFloat(l.budget_max);
  if (new Date(l.created_at).getTime() > now - 24*60*60*1000) pipeline.leads_last_24h++;
});

pipeline.avg_score = scoreCount > 0 ? Math.round(scoreSum / scoreCount) : 0;

return [{ json: {
  pipeline,
  sample_leads: leads.slice(0, 5).map(l => `${l.name} (${l.ai_priority}/${l.status}, Score:${l.ai_score})`).join('; ')
}}];

