const ai = $input.first().json;
const data = $node['Aggregate 360 Data'].json;
let insight;
try { insight = ai.choices[0].message.content.trim(); } catch(e) { insight = 'AI analysis unavailable.'; }

const p = data.pipeline;
return [{ json: {
  slackMessage: `📊 *Customer 360 Report*\n\n*Pipeline:* ${p.total} leads | 🔥 HOT: ${p.by_priority.HOT} | 🟡 WARM: ${p.by_priority.WARM} | 🔵 COLD: ${p.by_priority.COLD}\n*Avg Score:* ${p.avg_score}/100 | *New (24h):* ${p.leads_last_24h}\n*Potential Revenue:* AED ${p.total_potential_revenue.toLocaleString()}\n*Odoo CRM:* ${p.odoo_leads} leads synced\n\n*🤖 AI Insight:*\n${insight}`,
  insight,
  pipeline: p
}}];
